export type GetEmailHistoryQueryError = ErrorType<ErrorResponse>;

/**
 * @summary Get email campaign history
 */

export function useGetEmailHistory<
  TData = Awaited<ReturnType<typeof getEmailHistory>>,
  TError = ErrorType<ErrorResponse>,
>(options?: {
  query?: UseQueryOptions<
    Awaited<ReturnType<typeof getEmailHistory>>,
    TError,
    TData
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseQueryResult<TData, TError> & { queryKey: QueryKey } {
  const queryOptions = getGetEmailHistoryQueryOptions(options);

  const query = useQuery(queryOptions) as UseQueryResult<TData, TError> & {
    queryKey: QueryKey;
  };

  return { ...query, queryKey: queryOptions.queryKey };
}

/**
 * @summary Send bulk email to attendees
 */
export const getSendEmailUrl = () => {
  return `/api/email/send`;
};

export const sendEmail = async (
  sendEmailRequest: SendEmailRequest,
  options?: RequestInit,
): Promise<SendEmailResponse> => {
  return customFetch<SendEmailResponse>(getSendEmailUrl(), {
    ...options,
    method: "POST",
    headers: { "Content-Type": "application/json", ...options?.headers },
    body: JSON.stringify(sendEmailRequest),
  });
};

export const getSendEmailMutationOptions = <
  TError = ErrorType<ErrorResponse>,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof sendEmail>>,
    TError,
    { data: BodyType<SendEmailRequest> },
    TContext
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationOptions<
  Awaited<ReturnType<typeof sendEmail>>,
  TError,
  { data: BodyType<SendEmailRequest> },
  TContext
> => {
  const mutationKey = ["sendEmail"];
  const { mutation: mutationOptions, request: requestOptions } = options
    ? options.mutation &&
      "mutationKey" in options.mutation &&
      options.mutation.mutationKey
      ? options
      : { ...options, mutation: { ...options.mutation, mutationKey } }
    : { mutation: { mutationKey }, request: undefined };

  const mutationFn: MutationFunction<
    Awaited<ReturnType<typeof sendEmail>>,
    { data: BodyType<SendEmailRequest> }
  > = (props) => {
    const { data } = props ?? {};

    return sendEmail(data, requestOptions);
  };

  return { mutationFn, ...mutationOptions };
};

export type SendEmailMutationResult = NonNullable<
  Awaited<ReturnType<typeof sendEmail>>
>;
export type SendEmailMutationBody = BodyType<SendEmailRequest>;
export type SendEmailMutationError = ErrorType<ErrorResponse>;

/**
 * @summary Send bulk email to attendees
 */
export const useSendEmail = <
  TError = ErrorType<ErrorResponse>,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof sendEmail>>,
    TError,
    { data: BodyType<SendEmailRequest> },
    TContext
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationResult<
  Awaited<ReturnType<typeof sendEmail>>,
  TError,
  { data: BodyType<SendEmailRequest> },
  TContext
> => {
  return useMutation(getSendEmailMutationOptions(options));
};
